<script setup lang="ts">
import {ref} from 'vue';const props=withDefaults(defineProps<{label?:string;variant?:'primary'|'secondary'|'outline'|'danger'|'ghost';size?:'xs'|'sm'|'base'|'lg';disabled?:boolean;loading?:boolean;iconOnly?:boolean;type?:'button'|'submit'|'reset'}>(),{label:'Primary',variant:'primary',size:'base',type:'button'});const count=ref(0);function activate(){if(!props.disabled&&!props.loading)count.value++}
</script>
<template><main class="button-shell"><h1>Button</h1><section class="button-matrix"><button :type="type" :class="['kumo-button',variant,size]" :disabled="disabled||loading" :aria-disabled="disabled||undefined" :aria-busy="loading||undefined" :aria-label="iconOnly?label:undefined" @click="activate"><span v-if="loading" aria-hidden="true">◌</span>{{loading?'Loading…':iconOnly?'＋':label}}<span v-if="count"> {{count}}</span></button><button v-for="v in ['secondary','outline','danger','ghost']" :key="v" type="button" :class="['kumo-button',v]">{{v}}</button></section></main></template>
